INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000001', 'فیزیک کوانتوم برای همه', 'دکتر علی احمدی', 'علمی', 45, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "مقدمه", "blocks": [{"type": "text", "content": "فیزیک کوانتوم شاخه‌ای از فیزیک است که به بررسی رفتار ذرات در مقیاس‌های اتمی و زیراتمی می‌پردازد. این کتاب با زبانی ساده مفاهیم پیچیده کوانتومی را توضیح می‌دهد تا هر علاقه‌مندی بتواند به دنیای شگفت‌انگیز ذرات وارد شود و از زیبایی‌های این علم لذت ببرد."}]}, {"title": "ذره و موج", "blocks": [{"type": "image", "url": "/seed-images/quantum1.svg", "caption": "رفتار دوگانه ذرات", "hotspots": [{"x": 30, "y": 40, "label": "موج", "description": "رفتار موجی الکترون"}, {"x": 70, "y": 50, "label": "ذره", "description": "رفتار ذره‌ای در آشکارساز"}]}]}, {"title": "اصل عدم قطعیت", "blocks": [{"type": "text", "content": "اصل عدم قطعیت هایزنبرگ یکی از ستون‌های فیزیک کوانتوم است. این اصل بیان می‌کند که نمی‌توان همزمان موقعیت و تکانه یک ذره را با دقت بی‌نهایت اندازه‌گیری کرد. هر چه دقت اندازه‌گیری موقعیت بیشتر باشد، عدم قطعیت در تکانه بیشتر خواهد بود و بالعکس."}]}, {"title": "نکته مهم", "blocks": [{"type": "callout", "content": "اصل عدم قطعیت یک محدودیت ذاتی طبیعت است نه محدودیت فناوری اندازه‌گیری.", "style": "warning"}]}, {"title": "درهم‌تنیدگی", "blocks": [{"type": "text", "content": "درهم‌تنیدگی کوانتومی پدیده‌ای شگفت‌انگیز است که در آن دو ذره به گونه‌ای با یکدیگر مرتبط می‌شوند که تغییر حالت یکی فوراً بر دیگری اثر می‌گذارد حتی اگر در فواصل دور از هم باشند. این پدیده توسط انیشتین «عمل شبح‌وار دور» نامیده شد."}]}]'::jsonb, 'book-1', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000002', 'زیست‌شناسی سلولی', 'دکتر مریم رضایی', 'علمی', 38, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "سلول زنده", "blocks": [{"type": "text", "content": "سلول کوچک‌ترین واحد ساختاری و عملکردی همه موجودات زنده است. هر سلول مانند یک کارخانه کوچک عمل می‌کند که در آن هزاران واکنش شیمیایی به طور همزمان در حال انجام است. غشای سلولی مانند یک نگهبان هوشمند، مواد مورد نیاز را وارد و مواد زائد را خارج می‌کند."}]}, {"title": "اندامک‌ها", "blocks": [{"type": "gallery", "images": [{"url": "/seed-images/cell1.svg", "caption": ""}, {"url": "/seed-images/cell2.svg", "caption": ""}, {"url": "/seed-images/cell3.svg", "caption": ""}]}]}, {"title": "میتوکندری", "blocks": [{"type": "text", "content": "میتوکندری نیروگاه سلول نامیده می‌شود. این اندامک کوچک و بیضی‌شکل، انرژی شیمیایی موجود در مواد غذایی را به انرژی قابل استفاده برای سلول تبدیل می‌کند. هر سلول ممکن است صدها تا هزاران میتوکندری داشته باشد بسته به میزان نیاز آن به انرژی."}]}, {"title": "مقایسه سلول‌ها", "blocks": [{"type": "table", "headers": ["ویژگی", "جانوری", "گیاهی"], "rows": [["دیواره سلولی", "ندارد", "دارد"], ["کلروپلاست", "ندارد", "دارد"], ["انبار نشاسته", "ندارد", "دارد"], ["ماده ژلاتینی", "اندک", "فراوان"]]}]}, {"title": "دانستنی", "blocks": [{"type": "callout", "content": "DNA انسان اگر باز شود، به اندازه فاصله زمین تا خورشید و حتی بیشتر طول خواهد داشت!", "style": "info"}]}]'::jsonb, 'book-2', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000003', 'نجوم مقدماتی', 'دکتر حسن محمدی', 'علمی', 32, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "آسمان شب", "blocks": [{"type": "text", "content": "نجوم قدیمی‌ترین علم است. انسان‌ها از هزاران سال پیش به آسمان نگاه می‌کردند و الگوهای ستارگان را رصد می‌کردند. این کتاب شما را به سفری در فضا می‌برد تا با سیاره‌ها، ستارگان، کهکشان‌ها و پدیده‌های عمیق جهان آشنا شوید."}]}, {"title": "سیارات", "blocks": [{"type": "slideshow", "slides": [{"url": "/seed-images/planet1.svg", "caption": ""}, {"url": "/seed-images/planet2.svg", "caption": ""}, {"url": "/seed-images/planet3.svg", "caption": ""}]}]}, {"title": "تاریخچه کشفیات", "blocks": [{"type": "timeline", "events": [{"year": "1543", "title": "مدل هلیوسنتریک", "description": "کپرنیک نظریه مرکزیت خورشید را مطرح کرد"}, {"year": "1609", "title": "تلسکوپ گالیله", "description": "گالیله با تلسکوپ خود حلقه‌های زحل را کشف کرد"}, {"year": "1687", "title": "قانون گرانش", "description": "نیوتون قوانین حرکت و گرانش جهانی را منتشر کرد"}, {"year": "1995", "title": "کشف سیاره فراخورشیدی", "description": "اولین سیاره خارج از منظومه شمسی کشف شد"}]}]}, {"title": "سیاه‌چاله‌ها", "blocks": [{"type": "text", "content": "سیاه‌چاله منطقه‌ای از فضازمان است که گرانش آن آنقدر قوی است که هیچ چیز حتی نور نمی‌تواند از آن فرار کند. مرز سیاه‌چاله «افق رویداد» نامیده می‌شود. زمان در نزدیکی یک سیاه‌چاله بسیار کندتر سپری می‌شود."}]}, {"title": "نکته", "blocks": [{"type": "callout", "content": "ستارگان پرجرم در پایان عمر خود می‌توانند به سیاه‌چاله تبدیل شوند.", "style": "warning"}]}]'::jsonb, 'book-3', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000004', 'شیمی آلی', 'دکتر سارا کریمی', 'علمی', 40, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "مولکول‌های زندگی", "blocks": [{"type": "text", "content": "شیمی آلی شاخه‌ای از شیمی است که به مطالعه ترکیبات کربن می‌پردازد. از DNA گرفته تا پلاستیک، از داروها گرفته تا رنگ‌ها، همه با شیمی آلی سر و کار دارند. این کتاب پایه‌های شیمی آلی را با مثال‌های کاربردی توضیح می‌دهد."}]}, {"title": "ساختار بنزن", "blocks": [{"type": "image", "url": "/seed-images/benzene.svg", "caption": "حلقه بنزن، سنگ بنای شیمی آلی", "hotspots": [{"x": 50, "y": 50, "label": "کربن", "description": "اتم کربن در حلقه بنزن"}]}]}, {"title": "هیدروکربن‌ها", "blocks": [{"type": "text", "content": "هیدروکربن‌ها ساده‌ترین ترکیبات آلی هستند که فقط از کربن و هیدروژن تشکیل شده‌اند. آلکان‌ها، آلکن‌ها و آلکین‌ها سه گروه اصلی هیدروکربن‌ها هستند. هر کدام ویژگی‌های شیمیایی منحصربه‌فردی دارند که در صنایع مختلف کاربرد فراوان دارند."}]}, {"title": "انواع هیدروکربن", "blocks": [{"type": "table", "headers": ["گروه", "پیوند", "فرمول"], "rows": [["آلکان", "تک", "CₙH₂ₙ₊₂"], ["آلکن", "دو", "CₙH₂ₙ"], ["آلکین", "سه", "CₙH₂ₙ₋₂"]]}]}, {"title": "کاربرد", "blocks": [{"type": "callout", "content": "پلی‌اتیلن پرمصرف‌ترین پلاستیک جهان است که از پلیمریزاسیون اتیلن به دست می‌آید.", "style": "info"}]}]'::jsonb, 'book-4', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000005', 'هوش مصنوعی و آینده', 'دکتر رضا نوری', 'علمی', 55, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "مقدمه بر AI", "blocks": [{"type": "text", "content": "هوش مصنوعی تلاش برای ساخت ماشین‌هایی است که بتوانند کارهایی را انجام دهند که normally به هوش انسانی نیاز دارند. از تشخیص تصویر گرفته تا پردازش زبان طبیعی، AI در حال تغییر دنیای ماست. این کتاب به بررسی تکنیک‌ها و آینده این فناوری می‌پردازد."}]}, {"title": "شبکه عصبی", "blocks": [{"type": "image", "url": "/seed-images/neural.svg", "caption": "معماری شبکه عصبی عمیق", "hotspots": [{"x": 40, "y": 30, "label": "لایه ورودی", "description": "دریافت داده‌های خام"}, {"x": 60, "y": 50, "label": "لایه پنهان", "description": "پردازش ویژگی‌ها"}]}]}, {"title": "یادگیری عمیق", "blocks": [{"type": "text", "content": "یادگیری عمیق زیرمجموعه‌ای از یادگیری ماشین است که از شبکه‌های عصبی با لایه‌های متعدد استفاده می‌کند. این مدل‌ها می‌توانند ویژگی‌های پیچیده را به طور خودکار از داده‌های خام استخراج کنند و در کارهایی مانند ترجمه ماشینی و رانندگی خودکار عملکرد فوق‌العاده‌ای دارند."}]}, {"title": "هشدار اخلاقی", "blocks": [{"type": "callout", "content": "توسعه AI باید با در نظر گرفتن مسائل اخلاقی، حریم خصوصی و عدالت اجتماعی صورت گیرد.", "style": "warning"}]}, {"title": "تکامل AI", "blocks": [{"type": "timeline", "events": [{"year": "1956", "title": "تولد AI", "description": "کنفرارت دارتموث اصطلاح AI را معرفی کرد"}, {"year": "1997", "title": "دیپ بلو", "description": "کامپیوتر گری کاسپاروف را در شطرنج شکست داد"}, {"year": "2012", "title": "انقلاب عمیق", "description": "الکس‌نت در ImageNet پیروز شد"}, {"year": "2022", "title": "ChatGPT", "description": "مدل‌های زبانی بزرگ به شهرت جهانی رسیدند"}]}]}]'::jsonb, 'book-5', 'fa', 'authored', true, true, 1)
