INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000006', 'ایران در گذر تاریخ', 'دکتر محمد طاهری', 'فرهنگی', 42, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "تمدن کهن", "blocks": [{"type": "text", "content": "ایران سرزمینی است با تاریخی هفت هزار ساله. از تمدن ایلام و جیرفت تا شکوه هخامنشیان و پارتی‌ها، این سرزمین همواره یکی از کانون‌های تمدن بشری بوده است. فرهنگ، هنر، معماری و ادبیات ایرانی تأثیر عمیقی بر تمدن‌های همسایه و جهان گذاشته است."}]}, {"title": "آثار باستانی", "blocks": [{"type": "gallery", "images": [{"url": "/seed-images/iran1.svg", "caption": ""}, {"url": "/seed-images/iran2.svg", "caption": ""}, {"url": "/seed-images/iran3.svg", "caption": ""}]}]}, {"title": "عصر هخامنشی", "blocks": [{"type": "text", "content": "امپراتوری هخامنشی بزرگ‌ترین امپراتوری جهان باستان بود که از مصر تا آسیای مرکزی و از یونان تا هندوستان گسترده بود. کوروش کبیر بنیان‌گذار این امپراتوری بود که با منشور حقوق بشر خود، نماد تسامح و آزادی در تاریخ شد."}]}, {"title": "خط زمانی", "blocks": [{"type": "timeline", "events": [{"year": "3200 ق.م", "title": "تمدن ایلام", "description": "تمدن کهن ایلام در غرب ایران شکل گرفت"}, {"year": "550 ق.م", "title": "هخامنشیان", "description": "کوروش امپراتوری بزرگ هخامنشی را بنیان نهاد"}, {"year": "247 ق.م", "title": "اشکانیان", "description": "پارتی‌ها قدرت را در ایران به دست گرفتند"}, {"year": "224 م", "title": "ساسانیان", "description": "اردشیر بابکان ساسانیان را تأسیس کرد"}]}]}]'::jsonb, 'book-6', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000007', 'هنر و ادبیات فارسی', 'دکتر لیلا موسوی', 'فرهنگی', 35, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "شعر پارسی", "blocks": [{"type": "text", "content": "ادبیات فارسی یکی از غنی‌ترین ادبیات جهان است. از رودکی و فردوسی گرفته تا حافظ و سعدی و مولانا، شاعران ایرانی با آثار جاودانه خود، زیبایی‌های زبان فارسی را به اوج رسانده‌اند. این کتاب به معرفی سبک‌ها و دستاوردهای شعر و نثر فارسی می‌پردازد."}]}, {"title": "خوشنویسی", "blocks": [{"type": "image", "url": "/seed-images/calligraphy.svg", "caption": "هنر خوشنویسی فارسی", "hotspots": [{"x": 50, "y": 50, "label": "نسخ", "description": "خط نسخ، ملکه خطوط اسلامی"}]}]}, {"title": "فردوسی و شاهنامه", "blocks": [{"type": "text", "content": "حکیم ابوالقاسم فردوسی با سرودن شاهنامه، حماسه ملی ایران را برای همیشه زنده نگه داشت. شاهنامه بزرگ‌ترین کتاب سروده شده به یک زبان است و حماسه‌ای است از تولد تا مرگ امپراتوری ساسانی."}]}, {"title": "غزل حافظ", "blocks": [{"type": "callout", "content": "«اگر آن ترک شیرازی به دل ما راه دهد...» یکی از مشهورترین غزلیات حافظ است که جهانیان آن را می‌شناسند.", "style": "info"}]}]'::jsonb, 'book-7', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000008', 'فرهنگ عامه ایران', 'دکتر پریسا امینی', 'فرهنگی', 28, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "سنت‌ها و آیین‌ها", "blocks": [{"type": "text", "content": "فرهنگ عامه شامل باورها، رسوم، داستان‌های عامیانه، ضرب‌المثل‌ها و بازی‌های سنتی است که از نسلی به نسل دیگر منتقل شده است. این کتاب به جستجوی ریشه‌های فرهنگ مردمی ایران در جشن‌ها، مراسم و سنت‌های روزمره می‌پردازد."}]}, {"title": "جشن‌های ایرانی", "blocks": [{"type": "gallery", "images": [{"url": "/seed-images/nowruz.svg", "caption": ""}, {"url": "/seed-images/yalda.svg", "caption": ""}, {"url": "/seed-images/chaharshanbe.svg", "caption": ""}]}]}, {"title": "نوروز", "blocks": [{"type": "text", "content": "نوروز کهن‌ترین جشن جهان است که با ورود بهار و تحویل سال نو جشن گرفته می‌شود. خانه‌تکانی، چیدن سفره هفت سین، دید و بازدید و عیدی دادن از رسوم اصلی این جشن هستند. نوروز در سال ۲۰۰۹ در فهرست میراث فرهنگی ناملموس یونسکو ثبت شد."}]}, {"title": "جشن‌های اصلی", "blocks": [{"type": "table", "headers": ["جشن", "زمان", "نماد"], "rows": [["نوروز", "اول فروردین", "تولد دوباره طبیعت"], ["یلدا", "آخر آذر", "پیروزی نور بر تاریکی"], ["چهارشنبه‌سوری", "آخر سال", "آتش و شادی"], ["مهرگان", "۱۶ مهر", "دوستی و مهربانی"]]}]}]'::jsonb, 'book-8', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000009', 'معماری اسلامی', 'دکتر امیر حسینی', 'فرهنگی', 48, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "هنر معماری", "blocks": [{"type": "text", "content": "معماری اسلامی ایران یکی از شاخص‌ترین سبک‌های معماری جهان است. مساجد، مدارس، کاروانسراها و باغ‌های ایرانی همگی نمادی از هماهنگی بین هنر، طبیعت و معنویت هستند. گنبد، مناره، ایوان و کاشی‌کاری از عناصر اصلی این سبک معماری هستند."}]}, {"title": "شاهکارهای معماری", "blocks": [{"type": "slideshow", "slides": [{"url": "/seed-images/arch1.svg", "caption": ""}, {"url": "/seed-images/arch2.svg", "caption": ""}, {"url": "/seed-images/arch3.svg", "caption": ""}]}]}, {"title": "مسجد امام اصفهان", "blocks": [{"type": "image", "url": "/seed-images/masjid.svg", "caption": "نمونه بی‌نظیر کاشی‌کاری", "hotspots": [{"x": 30, "y": 30, "label": "گنبد", "description": "گنبد فیروزه‌ای رنگ"}, {"x": 70, "y": 60, "label": "مناره", "description": "مناره‌های قرینه"}]}]}, {"title": "باغ ایرانی", "blocks": [{"type": "text", "content": "باغ ایرانی نماد بهشت بر روی زمین است. چهارباغ، آب و درختان مرکز آن را تشکیل می‌دهند. باغ‌های کاشان، شیراز و ماهان هنوز الهام‌بخش معماران جهان هستند."}]}]'::jsonb, 'book-9', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000010', 'فوتبال تاکتیکی', 'علی کریمی', 'ورزشی', 30, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "تاکتیک مدرن", "blocks": [{"type": "text", "content": "فوتبال امروز دیگر فقط سرعت و قدرت نیست. آنالیز داده‌ها، تاکتیک‌های پیچیده و سیستم‌های بازی متنوع، فوتبال را به یک علم تبدیل کرده‌اند. این کتاب به بررسی سیستم‌های ۴-۳-۳، ۳-۵-۲ و ۴-۲-۳-۱ می‌پردازد."}]}, {"title": "چیدمان تیم", "blocks": [{"type": "image", "url": "/seed-images/tactic.svg", "caption": "چیدمان ۴-۳-۳ هجومی", "hotspots": [{"x": 50, "y": 20, "label": "مهاجم", "description": "مهاجم نوک"}, {"x": 35, "y": 50, "label": "هافبک", "description": "هافبک کناری"}]}]}, {"title": "سیستم‌های محبوب", "blocks": [{"type": "table", "headers": ["سیستم", "نقاط قوت", "نقاط ضعف"], "rows": [["۴-۳-۳", "کنترل میانه", "آسیب‌پذیری کناری"], ["۳-۵-۲", "تراکمی مرکز", "نیاز به وینگ‌بک"], ["۴-۲-۳-۱", "تعادل", "پیچیدگی ارتباط"]]}]}, {"title": "پرسینگ", "blocks": [{"type": "text", "content": "پرسینگ یا فشار روی توپ یکی از تاکتیک‌های اصلی فوتبال مدرن است. تیم لیورپول تحت هدایت کلوپ و تیم منچسترسیتی تحت گواردیولا، دو نمونه برجسته از اجرای موفق پرسینگ هستند که بازی را در زمین حریف شکل می‌دهند."}]}, {"title": "نکته مربیگری", "blocks": [{"type": "callout", "content": "پرسینگ موفق نیازمند آمادگی بدنی بالا و هماهنگی تیمی است.", "style": "info"}]}]'::jsonb, 'book-10', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000011', 'کشتی آزاد', 'رسول خادم', 'ورزشی', 25, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "تاریخچه کشتی", "blocks": [{"type": "text", "content": "کشتی یکی از کهن‌ترین ورزش‌های جهان است که ریشه در تاریخ ایران دارد. ورزشگاه‌های پهلوانی، آیین‌های زورخانه و مراسم گلیم‌کش نشان از قدمت این ورزش در فرهنگ ایرانی دارد. این کتاب به تاریخ و تکنیک‌های کشتی آزاد و فرنگی می‌پردازد."}]}, {"title": "افتخارات", "blocks": [{"type": "gallery", "images": [{"url": "/seed-images/wrestle1.svg", "caption": ""}, {"url": "/seed-images/wrestle2.svg", "caption": ""}, {"url": "/seed-images/wrestle3.svg", "caption": ""}]}]}, {"title": "تکنیک‌های پایه", "blocks": [{"type": "text", "content": "کشتی آزاد شامل تکنیک‌های ایستاده و زمینی است. تاخت، ضربه آوردن، گردن‌گیری و خاک‌کردن از حرکات اصلی هستند. هر کشتی‌گیر باید در کنار قدرت بدنی، تاکتیک و زیرکی بالایی داشته باشد."}]}, {"title": "قهرمانان", "blocks": [{"type": "callout", "content": "حمید سوریان، حسن یزدانی و امیرحسین زارع از ستارگان کشتی ایران در دهه اخیر هستند.", "style": "info"}]}]'::jsonb, 'book-11', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000012', 'دوچرخه‌سواری کوهستان', 'مهدی احمدی', 'ورزشی', 22, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "شروع دوچرخه‌سواری", "blocks": [{"type": "text", "content": "دوچرخه‌سواری کوهستان یکی از هیجان‌انگیزترین ورزش‌ها است که ترکیبی از تمرین بدنی، شجاعت و عشق به طبیعت است. این کتاب راهنمای کاملی برای مبتدیان و حرفه‌ای‌هاست که از انتخاب دوچرخه تا تکنیک‌های حرفه‌ای سربالایی و سرپایینی را پوشش می‌دهد."}]}, {"title": "تجهیزات", "blocks": [{"type": "image", "url": "/seed-images/bike.svg", "caption": "دوچرخه کوهستان با کمک‌فنر", "hotspots": [{"x": 40, "y": 40, "label": "تایر", "description": "تایر آفرود"}, {"x": 60, "y": 30, "label": "ترمز", "description": "ترمز دیسکی"}]}]}, {"title": "تکنیک سربالایی", "blocks": [{"type": "text", "content": "در سربالایی، تعادل و توزیع صحیح وزن کلید اصلی است. باید روی زین بنشینید و نیرو را به صورت یکنواخت از طریق پدال‌ها منتقل کنید. دنده سبک‌تر و دور پدال بالاتر کمک می‌کند انرژی خود را مدیریت کنید."}]}, {"title": "ایمنی", "blocks": [{"type": "callout", "content": "همیشه کلاه ایمنی بپوشید و قبل از هر مسیر، دوچرخه خود را چک کنید.", "style": "warning"}]}]'::jsonb, 'book-12', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000013', 'حسابان پیشرفته', 'دکتر حسن محمودی', 'ریاضی', 35, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "محدود و پیوستگی", "blocks": [{"type": "text", "content": "حسابان شاخه‌ای از ریاضیات است که به مطالعه تغییرات می‌پردازد. مفاهیم حد، پیوستگی، مشتق و انتگرال ستون‌های این علم هستند. این کتاب با مثال‌های کاربردی از فیزیک و اقتصاد، درک عمیقی از حسابان ایجاد می‌کند."}]}, {"title": "نمودار تابع", "blocks": [{"type": "image", "url": "/seed-images/calc.svg", "caption": "نمودار تابع و مشتق", "hotspots": [{"x": 50, "y": 30, "label": "نقطه بحرانی", "description": "جایی که مشتق صفر است"}]}]}, {"title": "مشتق و کاربردها", "blocks": [{"type": "text", "content": "مشتق نرخ تغییرات یک تابع را اندازه می‌گیرد. با مشتق می‌توانیم نقاط بحرانی را پیدا کنیم، بیشینه و کمینه را تعیین کنیم و شکل نمودار را تحلیل کنیم. در فیزیک، مشتق مکان بر حسب زمان، سرعت و مشتق سرعت، شتاب است."}]}, {"title": "قوانین مشتق", "blocks": [{"type": "table", "headers": ["قانون", "فرمول"], "rows": [["توان", "d/dx xⁿ = n·xⁿ⁻¹"], ["ضرب ثابت", "d/dx c·f = c·f''"], ["جمع", "d/dx (f+g) = f''+g''"], ["حاصلضرب", "d/dx f·g = f''·g + f·g''"]]}]}, {"title": "کاربرد", "blocks": [{"type": "callout", "content": "شرکت‌ها از مشتق برای یافتن سطح تولید با بیشترین سود استفاده می‌کنند.", "style": "info"}]}]'::jsonb, 'book-13', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000014', 'هندسه تحلیلی', 'دکتر فاطمه عباسی', 'ریاضی', 30, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "صفحه مختصات", "blocks": [{"type": "text", "content": "هندسه تحلیلی هندسه را با جبر و معادلات ترکیب می‌کند. با تعریف نقاط به صورت مختصات عددی، می‌توان اشکال هندسی را با معادلات توصیف کرد. خط، دایره، بیضی، سهمی و هذلولی منحنی‌های مخروطی هستند که پایه فیزیک نجومی هستند."}]}, {"title": "مخروطی‌ها", "blocks": [{"type": "image", "url": "/seed-images/conic.svg", "caption": "منحنی‌های مخروطی", "hotspots": [{"x": 30, "y": 50, "label": "بیضی", "description": "بیضی: مجموع فاصله‌ها ثابت"}, {"x": 70, "y": 40, "label": "هذلولی", "description": "هذلولی: تفاضل فاصله‌ها ثابت"}]}]}, {"title": "معادله خط", "blocks": [{"type": "text", "content": "معادله عمومی خط در صفحه به صورت y = mx + b است که در آن m شیب و b عرض از مبدأ است. شیب خط نشان‌دهنده زاویه آن با محور افقی است و نقش مهمی در تعیین موقعیت نسبی خطوط دارد."}]}, {"title": "مخروطی‌ها", "blocks": [{"type": "table", "headers": ["منحنی", "معادله", "خراش"], "rows": [["دایره", "x²+y²=r²", "e=0"], ["بیضی", "x²/a²+y²/b²=1", "0<e<1"], ["سهمی", "y²=4px", "e=1"], ["هذلولی", "x²/a²-y²/b²=1", "e>1"]]}]}]'::jsonb, 'book-14', 'fa', 'authored', true, true, 1)
