INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000015', 'آمار و احتمال', 'دکتر سمیه کاظمی', 'ریاضی', 28, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "دنیای داده", "blocks": [{"type": "text", "content": "در عصر اطلاعات، آمار و احتمال ابزارهای ضروری برای تصمیم‌گیری هستند. از پیش‌بینی آب و هوا گرفته تا تحلیل بازار سهام و پزشکی شخصی‌سازی‌شده، همه جا از این علوم استفاده می‌شود. این کتاب مفاهیم پایه تا پیشرفته را پوشش می‌دهد."}]}, {"title": "توزیع نرمال", "blocks": [{"type": "image", "url": "/seed-images/stats.svg", "caption": "منحنی زنگوله‌ای", "hotspots": [{"x": 50, "y": 50, "label": "میانگین μ", "description": "مرکز توزیع"}, {"x": 70, "y": 30, "label": "انحراف معیار", "description": "پراکندگی داده‌ها"}]}]}, {"title": "احتمال شرطی", "blocks": [{"type": "text", "content": "احتمال شرطی احتمال وقوع یک رویداد را با فرض وقوع رویداد دیگر اندازه می‌گیرد. قضیه بیز یکی از مهم‌ترین ابزارها در استنتاج آماری است که اجازه می‌دهد باورهای خود را در مواجهه با شواهد جدید به‌روز کنیم."}]}, {"title": "پارادوکس تولد", "blocks": [{"type": "callout", "content": "در یک گروه ۲۳ نفره، احتمال اینکه حداقل دو نفر در یک روز تولد باشند بیش از ۵۰٪ است!", "style": "info"}]}, {"title": "میانگین‌ها", "blocks": [{"type": "table", "headers": ["نوع", "فرمول", "حساسیت"], "rows": [["حسابی", "Σx/n", "داده پرت"], ["هندسی", "Πx^(1/n)", "نرخ رشد"], ["میانه", "مرکز داده‌ها", "بسیار پایدار"]]}]}]'::jsonb, 'book-15', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000016', 'فیزیک دبیرستان', 'دکتر احمد صادقی', 'درسی', 18, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "مکانیک", "blocks": [{"type": "text", "content": "مکانیک شاخه‌ای از فیزیک است که به حرکت اجسام می‌پردازد. قوانین نیوتن سه قانون بنیادین حرکت هستند که جهان مادی را توضیح می‌دهند. این فصل با مثال‌های ساده و آزمایش‌های عملی، مفاهیم نیرو، شتاب و انرژی را آموزش می‌دهد."}]}, {"title": "سقوط آزاد", "blocks": [{"type": "image", "url": "/seed-images/physics1.svg", "caption": "شمشیر و پر", "hotspots": [{"x": 40, "y": 40, "label": "شتاب g", "description": "شتاب گرانش ≈ 9.8 m/s²"}]}]}, {"title": "قانون اول نیوتن", "blocks": [{"type": "text", "content": "هر جسم در حالت سکون یا حرکت یکنواخت باقی می‌ماند مگر آنکه نیرویی خارجی به آن وارد شود. این قانون مفهوم اینرسی را معرفی می‌کند. در واقع اجسام «تنبل» هستند و حالت خود را دوست دارند حفظ کنند."}]}, {"title": "قوانین نیوتن", "blocks": [{"type": "table", "headers": ["قانون", "خلاصه"], "rows": [["اول", "اینرسی"], ["دوم", "F=ma"], ["سوم", "کنش و واکنش"]]}]}, {"title": "آزمایش", "blocks": [{"type": "callout", "content": "قرار دادن سکه روی کاغذ روی لیوان و کشیدن ناگهانی کاغرد نشان‌دهنده اینرسی است.", "style": "info"}]}]'::jsonb, 'book-16', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000017', 'شیمی دبیرستان', 'دکتر نازنین رحمانی', 'درسی', 16, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "جدول تناوبی", "blocks": [{"type": "text", "content": "جدول تناوبی نقشه عناصر شیمیایی است که بر اساس عدد اتمی و خواص شیمیایی مرتب شده‌اند. عناصر در گروه‌ها و دوره‌هایی قرار دارند که ویژگی‌های مشترکی دارند. فلزات در سمت چپ، نافلزات در سمت راست و شبه‌فلزات در وسط قرار دارند."}]}, {"title": "جدول مندلیف", "blocks": [{"type": "image", "url": "/seed-images/chem1.svg", "caption": "جدول تناوبی عناصر", "hotspots": [{"x": 20, "y": 50, "label": "فلزات قلیایی", "description": "گروه یک، بسیار واکنش‌پذیر"}, {"x": 80, "y": 50, "label": "گازهای نجیب", "description": "گروه ۱۸، بسیار پایدار"}]}]}, {"title": "پیوند شیمیایی", "blocks": [{"type": "text", "content": "اتم‌ها برای رسیدن به پیکره پایدار، با یکدیگر پیوند برقرار می‌کنند. پیوند یونی از جاذبه الکترواستاتیکی بین یون‌های مثبت و منفی، پیوند کووالانسی از اشتراک الکترون‌ها و پیوند فلزی از الکترون‌های آزاد در شبکه فلزی تشکیل می‌شود."}]}, {"title": "انواع پیوند", "blocks": [{"type": "table", "headers": ["نوع", "مثال", "رسانایی"], "rows": [["یونی", "NaCl", "در آب"], ["کووالانسی", "H₂O", "ضعیف"], ["فلزی", "Cu", "بالا"], ["هیدروژنی", "DNA", "خاص"]]}]}]'::jsonb, 'book-17', 'fa', 'authored', true, true, 1)
