INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000018', 'ریاضی پیش‌دانشگاهی', 'دکتر کامران لطفی', 'درسی', 20, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "توابع نمایی", "blocks": [{"type": "text", "content": "توابع نمایی توابعی به صورت f(x)=aˣ هستند که در مدل‌سازی رشد جمعیت، واپاشی رادیواکتیو و بهره مرکب کاربرد فراوان دارند. پایه e≈2.71828 توابع نموی طبیعی است که در حسابان نقش کلیدی دارد."}]}, {"title": "نمودار نمایی", "blocks": [{"type": "image", "url": "/seed-images/exp.svg", "caption": "رشد نمایی در مقابل خطی", "hotspots": [{"x": 30, "y": 60, "label": "نمایی", "description": "رشد فزاینده"}, {"x": 70, "y": 40, "label": "خطی", "description": "رشد ثابت"}]}]}, {"title": "مثلثات", "blocks": [{"type": "text", "content": "مثلثات رابطه بین زوایا و اضلاع مثلث را مطالعه می‌کند. سینوس، کسینوس و تانژانت سه نسبت مثلثاتی اصلی هستند که در فیزیک، مهندسی و نجوم کاربرد دارند. واحد رادیان واحد طبیعی زاویه در ریاضیات پیشرفته است."}]}, {"title": "ارزش‌های خاص", "blocks": [{"type": "table", "headers": ["زاویه", "sin", "cos", "tan"], "rows": [["۰", "0", "1", "0"], ["π/6", "1/2", "√3/2", "√3/3"], ["π/4", "√2/2", "√2/2", "1"], ["π/3", "√3/2", "1/2", "√3"], ["π/2", "1", "0", "∞"]]}]}, {"title": "فرمول اویلر", "blocks": [{"type": "callout", "content": "e^(iπ) + 1 = 0 زیباترین معادله ریاضی است که پنج ثابت مهم را به هم پیوند می‌دهد.", "style": "info"}]}]'::jsonb, 'book-18', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000019', 'زیست‌شناسی دبیرستان', 'دکتر مهشاد قاسمی', 'درسی', 17, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "سلول", "blocks": [{"type": "text", "content": "زیست‌شناسی علم مطالعه حیات است. همه موجودات زنده از سلول تشکیل شده‌اند. سلول‌های یوکاریوتی دارای هسته و اندامک‌های غشایی هستند در حالی که پروکاریوتی‌ها ساده‌ترند. این فصل ساختار و عملکرد سلول را معرفی می‌کند."}]}, {"title": "اندامک‌ها", "blocks": [{"type": "gallery", "images": [{"url": "/seed-images/bio1.svg", "caption": ""}, {"url": "/seed-images/bio2.svg", "caption": ""}, {"url": "/seed-images/bio3.svg", "caption": ""}]}]}, {"title": "DNA و وراثت", "blocks": [{"type": "text", "content": "DNA مولکول حامل اطلاعات ژنتیکی است که از نوکلئوتیدهای A، T، C و G تشکیل شده. ساختار مارپیچ دوگانه واتسون-کریک انقلابی در زیست‌شناسی بود. ژن‌ها قطعاتی از DNA هستند که پروتئین‌های خاصی را کد می‌کنند."}]}, {"title": "کشف", "blocks": [{"type": "callout", "content": "رزالیند فرانکلین تصاویر اشعه ایکس DNA را تهیه کرد که کلید کشف ساختار دوگانه بود.", "style": "info"}]}]'::jsonb, 'book-19', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000020', 'پزشکی خانواده', 'دکتر محمدرضا قاسمی', 'پزشکی', 38, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "سلامت خانواده", "blocks": [{"type": "text", "content": "پزشکی خانواده شاخه‌ای از پزشکی است که به ارائه مراقبت جامع برای همه اعضای خانواده می‌پردازد. این کتاب به پیشگیری از بیماری‌ها، تغذیه سالم، ورزش منظم، خواب کافی و مدیریت استرس برای حفظ سلامت خانواده می‌پردازد."}]}, {"title": "سلامت", "blocks": [{"type": "image", "url": "/seed-images/health.svg", "caption": "سبک زندگی سالم", "hotspots": [{"x": 30, "y": 40, "label": "تغذیه", "description": "میوه و سبزیجات"}, {"x": 70, "y": 50, "label": "ورزش", "description": "تحرک روزانه"}]}]}, {"title": "تغذیه سالم", "blocks": [{"type": "text", "content": "رژیم غذایی متعادل شامل میوه‌ها، سبزیجات، غلات کامل، پروتئین کم‌چرب و لبنیات است. مصرف قند اضافی، نمک زیاد و چربی‌های ترانس را محدود کنید. آب کافی بنوشید و وعده‌های غذایی منظم داشته باشید."}]}, {"title": "ویتامین‌های ضروری", "blocks": [{"type": "table", "headers": ["ویتامین", "منبع", "نقش"], "rows": [["C", "مرکبات", "آنتی‌اکسیدان"], ["D", "آفتاب", "استخوان"], ["B12", "گوشت", "عصب"], ["آهن", "سبزیجات", "خون"]]}]}, {"title": "هشدار", "blocks": [{"type": "callout", "content": "قبل از مصرف هر مکمل با پزشک مشورت کنید. مصرف بیش از حد ویتامین می‌تواند مضر باشد.", "style": "warning"}]}]'::jsonb, 'book-20', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000021', 'داروشناسی گیاهی', 'دکتر زهرا میرزایی', 'پزشکی', 32, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "طب سنتی", "blocks": [{"type": "text", "content": "گیاهان دارویی هزاران سال است که در درمان بیماری‌ها استفاده می‌شوند. زعفران، بادرنجبویه، گل‌محمدی، آویشن و زیره از گیاهان پرکاربرد ایران هستند. این کتاب با رویکرد علمی، خواص دارویی گیاهان بومی را بررسی می‌کند."}]}, {"title": "گیاهان دارویی", "blocks": [{"type": "gallery", "images": [{"url": "/seed-images/herb1.svg", "caption": ""}, {"url": "/seed-images/herb2.svg", "caption": ""}, {"url": "/seed-images/herb3.svg", "caption": ""}]}]}, {"title": "زعفران", "blocks": [{"type": "text", "content": "زعفران گران‌ترین ادویه جهان است. خواص ضدافسردگی، آنتی‌اکسیدانی و ضدالتهابی آن ثابت شده است. مصرف روزانه ۳۰ میلی‌گرم زعفران می‌تواند خلق‌وخو را بهبود بخشد و از دژنراسیون ماکولار جلوگیری کند."}]}, {"title": "احتیاط", "blocks": [{"type": "callout", "content": "مصرف همزمان داروهای گیاهی با داروهای شیمیایی ممکن است تداخل ایجاد کند. حتماً با پزشک مشورت کنید.", "style": "warning"}]}]'::jsonb, 'book-21', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000022', 'قلب و عروق', 'دکتر امیرعلی نوری', 'پزشکی', 45, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "قلب انسان", "blocks": [{"type": "text", "content": "قلب عضوی حفره‌دار و توخالی است که به اندازه مشت بسته است و روزانه حدود صد هزار بار می‌تپد. این کتاب به تشریح ساختار قلب، سیستم الکتریکی آن، بیماری‌های قلبی-عروقی و راه‌های پیشگیری می‌پردازد."}]}, {"title": "آناتومی قلب", "blocks": [{"type": "image", "url": "/seed-images/heart.svg", "caption": "بخش‌های قلب", "hotspots": [{"x": 40, "y": 40, "label": "دهلیز چپ", "description": "دریافت خون اکسیژنه"}, {"x": 60, "y": 60, "label": "بطن چپ", "description": "پمپاژ به بدن"}]}]}, {"title": "فشار خون", "blocks": [{"type": "text", "content": "فشار خون نیروی جریان خون در دیواره سرخرگ‌هاست. فشار طبیعی کمتر از ۱۲۰/۸۰ میلی‌متر جیوه است. فشار بالا «قاتل خاموش» نامیده می‌شود چون علامتی ندارد اما سکته، نارسایی کلیوی و نارسایی قلبی را به دنبال دارد."}]}, {"title": "طبقه‌بندی", "blocks": [{"type": "table", "headers": ["گروه", "فشار سیستول", "فشار دیاستول"], "rows": [["طبیعی", "<120", "<80"], ["مرحله ۱", "120-129", "<80"], ["مرحله ۲", "130-139", "80-89"], ["بحرانی", "≥140", "≥90"]]}]}, {"title": "پیشگیری", "blocks": [{"type": "callout", "content": "کاهش نمک، ورزش منظم، ترک سیگار و کنترل استرس از مهم‌ترین راه‌های پیشگیری از فشار خون هستند.", "style": "info"}]}]'::jsonb, 'book-22', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000023', 'شب‌های تهران', 'رضا امیرخانی', 'داستان', 25, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "شروع داستان", "blocks": [{"type": "text", "content": "تهران در یک شب بارانی. خیابان‌های خیس از نور چراغ‌ها می‌درخشند. علی در ایستگاه اتوبوس ایستاده و به قطرات باران روی شیشه خیره شده. ذهنش در گذشته سرگردان است و تصویر زنی که هرگز ندیده، در خواب‌هایش ظاهر می‌شود."}]}, {"title": "ایستگاه", "blocks": [{"type": "image", "url": "/seed-images/tehran1.svg", "caption": "ایستگاه اتوبوس در شب", "hotspots": [{"x": 50, "y": 50, "label": "علی", "description": "مردی که منتظر است"}]}]}, {"title": "برخورد", "blocks": [{"type": "text", "content": "اتوبوس رسید و درها باز شدند. علی سوار شد و در ردیف پشتی کنار پنجره نشست. زنی با چتر قرمز سوار شد و در همان ردیف نشست. نگاهشان در آینه اتوبوس به هم خورد و هر دو لبخند زدند."}]}, {"title": "گفتگو", "blocks": [{"type": "text", "content": "«باران زیباست» گفت زن. علی جواب داد: «مخصوصاً وقتی کسی باشد که زیر چترش با شما پناه ببرد.» زن خندید و گفت: «شما خیلی رمانتیک هستید.» علی گفت: «فقط در شب‌های بارانی.»"}]}, {"title": "پایان", "blocks": [{"type": "callout", "content": "آن شب آغاز داستانی بود که سال‌ها ادامه یافت. دو نفر زیر یک چتر، در شبی که هیچ‌کدام فراموش نکردند.", "style": "info"}]}]'::jsonb, 'book-23', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000024', 'سفر به اعماق زمین', 'حسن محمودی', 'داستان', 22, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "ماجراجویی", "blocks": [{"type": "text", "content": "دکتر احمدی باستان‌شناس، در حفاری‌های تخت جمشید تکه سنگی عجیب پیدا کرد. روی سنگ نقشه‌ای حک شده بود که به غاری ناشناخته در کوه‌های زاگرس اشاره داشت. او تصمیم گرفت راز این نقشه را کشف کند."}]}, {"title": "نقشه سنگی", "blocks": [{"type": "image", "url": "/seed-images/map.svg", "caption": "نقشه رمزآلود", "hotspots": [{"x": 40, "y": 40, "label": "نماد خورشید", "description": "نشانه مهم"}, {"x": 70, "y": 60, "label": "مسیر", "description": "راه پنهان"}]}]}, {"title": "غار پنهان", "blocks": [{"type": "text", "content": "پس از سه روز کوهنوردی، دکتر احمدی به دهانه غاری رسید که پشت بوته‌های گون پنهان شده بود. داخل غار، دیوارها با نقاشی‌های هزاره‌ها پیش از میلاد تزئین شده بودند. اسب‌های در حال دویدن، شکارچیان و آیین‌های مذهبی."}]}, {"title": "نقاشی‌ها", "blocks": [{"type": "slideshow", "slides": [{"url": "/seed-images/cave1.svg", "caption": ""}, {"url": "/seed-images/cave2.svg", "caption": ""}, {"url": "/seed-images/cave3.svg", "caption": ""}]}]}, {"title": "کشف بزرگ", "blocks": [{"type": "text", "content": "در انتهای غار، صندوقچه سنگی کوچکی پیدا کرد. داخل آن طلسم‌های طلا و لوحی به زبان میخی بود. این کشف تاریخ هنر ایران را بازنویسی می‌کرد. دکتر احمدی با احترام صندوقچه را در جای خود گذاشت و فقط عکس برداشت."}]}]'::jsonb, 'book-24', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000025', 'عشق در پاییز', 'سارا بهشتی', 'داستان', 20, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "ملاقات", "blocks": [{"type": "text", "content": "مریم هر روز صبح در کافه کوچک انتهای خیابان قهوه می‌خورد. یک روز پاییز، مردی با لپ‌تاپ در میز روبرو نشست. چشم‌هایش سبز بود و لبخندش گرم. هر دو به کتاب‌هایشان خیره بودند ولی نگاهشان گاه به هم می‌رسید."}]}, {"title": "کافه", "blocks": [{"type": "image", "url": "/seed-images/cafe.svg", "caption": "کافه کوچک پاییزی", "hotspots": [{"x": 30, "y": 50, "label": "مریم", "description": "دختری با کتاب شعر"}, {"x": 70, "y": 50, "label": "مرد", "description": "مردی با لپ‌تاپ"}]}]}, {"title": "اشعار", "blocks": [{"type": "text", "content": "مریم کتاب شعر حافظ باز کرد. مرد گفت: «حافظ؟ من هم عاشق حافظم.» مریم گفت: «شعر مورد علاقه‌تان؟» مرد بدون فکر گفت: «اگر آن ترک شیرازی...» مریم خندید: «این همه نگاه؟ فقط برای حافظ؟»"}]}, {"title": "پاییز تمام شد", "blocks": [{"type": "text", "content": "پاییز تمام شد و برف آمد. مریم دیگر تنها نبود. هر روز صبح، دو فنجان قهوه روی میز بود. یکی برای او و یکی برای مردی که حافظ را از حفظ می‌دانست."}]}]'::jsonb, 'book-25', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000026', 'ماجرای نیمه‌شب', 'کیوان عباسی', 'داستان', 18, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "زنگ تلفن", "blocks": [{"type": "text", "content": "ساعت دو نیمه‌شب بود. تلفن زنگ زد. محمد گوشی را برداشت. سکوت. سپس نفسی عمیق و صدایی خشن: «فردا می‌آییم. همه چیز را می‌خواهیم.» خط قطع شد. محمد لرزید. او می‌دانست این تماس درباره چیست."}]}, {"title": "تاریکی", "blocks": [{"type": "image", "url": "/seed-images/dark.svg", "caption": "اتاق تاریک در نیمه‌شب", "hotspots": [{"x": 50, "y": 50, "label": "تلفن", "description": "تلفن روی میز"}]}]}, {"title": "تصمیم", "blocks": [{"type": "text", "content": "محمد به گذشته فکر کرد. پانزده سال پیش تصمیمی گرفت که حالا داشت او را دنبال می‌کرد. کیف چرمینه را از کمد بیرون آورد. داخلش مدارک، عکس‌ها و نامه‌هایی بود که هیچ‌کس نباید می‌دید. صبح زود باید می‌رفت."}]}, {"title": "فرار", "blocks": [{"type": "text", "content": "ساعت پنج صبح، محمد ماشین را روشن کرد. باران شدید بود. جاده‌های کوهستانی لغزنده. ولی پشت سر نگاه نکرد. فقط رفت. گاهی در زندگی باید فرار کرد تا زنده ماند. و گاهی فرار کردن شجاعانه‌ترین کار است."}]}, {"title": "پایان باز", "blocks": [{"type": "callout", "content": "جاده به کجا می‌رفت؟ محمد نمی‌دانست. ولی برای اولین بار پس از سال‌ها، احساس آزادی می‌کرد.", "style": "info"}]}]'::jsonb, 'book-26', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000027', 'خاطرات یک سرباز', 'مهدی نوری', 'داستان', 24, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "اعزام", "blocks": [{"type": "text", "content": "ساعت چهار صبح بود که زنگ بیدار باش نواخت. بیست ساله بودم و فردا باید برای سربازی می‌رفتم. مادرم اشک می‌ریخت و پدرم سکوت کرده بود. کیفم را بستم و سوار اتوبوس شدم. نمی‌دانستم دو سال بعد چه انسان متفاوتی خواهم بود."}]}, {"title": "پادگان", "blocks": [{"type": "image", "url": "/seed-images/army.svg", "caption": "روز اول سربازی", "hotspots": [{"x": 40, "y": 50, "label": "اتوبوس", "description": "اتوبوس اعزام"}, {"x": 70, "y": 40, "label": "سربازان", "description": "جوانان نگران"}]}]}, {"title": "دوستان", "blocks": [{"type": "text", "content": "در پادگان با پسرهایی آشنا شدم که هر کدام داستانی داشتند. حسن از روستا بود و اولین بار شهر دیده بود. رضا دانشجوی ریاضی بود که شعر می‌گفت. علی از تهران بود و همیشه حرف حق می‌زد. با هم رفقای جدایی‌ناپذیر شدیم."}]}, {"title": "آموزش", "blocks": [{"type": "text", "content": "تمرین نظامی سخت بود. تیراندازی، رزم، شب‌مانی. ولی در همین سختی‌ها بود که فهمیدم چقدر قوی‌تر از آن چیزی هستم که فکر می‌کردم. سربازی فقط آموزش نظامی نیست؛ مدرسه زندگی است."}]}, {"title": "خداحافظی", "blocks": [{"type": "text", "content": "روز آزادی رسید. مادرم منتظرم بود. وقتی او را در آغوش گرفتم، فهمیدم سربازی به من یاد داد قدر خانواده و وطن را بدانم. سربازی پایان یک دوران و آغاز دوران بزرگسالی بود."}]}]'::jsonb, 'book-27', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000028', 'سرزمین قصه‌ها', 'مینا کوچولو', 'کودک', 12, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "روزی روزگاری", "blocks": [{"type": "text", "content": "روزی بود و روزی نبود، زیر آسمان آبی، سرزمینی بود پر از رنگ و موسیقی. در آنجا درخت‌ها حرف می‌زدند، پروانه‌ها می‌خندیدند و ابرها قصه تعریف می‌کردند. به این سرزمین زیبا خوش آمدی! بیا با هم سفری شگفت‌انگیز داشته باشیم."}]}, {"title": "پروانه‌های رنگی", "blocks": [{"type": "image", "url": "/seed-images/kid1.svg", "caption": "پروانه‌های بازیگوش", "hotspots": [{"x": 20, "y": 30, "label": "پروانه آبی", "description": "روی گل نشسته"}, {"x": 60, "y": 40, "label": "پروانه زرد", "description": "در حال پرواز"}, {"x": 80, "y": 70, "label": "گل صورتی", "description": "گل معطر و زیبا"}]}]}, {"title": "سفر ابر کوچولو", "blocks": [{"type": "text", "content": "ابر کوچولو همیشه دوست داشت به جاهای دور سفر کند. یک روز باد مهربان او را بلند کرد و برد. ابر کوچولو از بالا شهر را دید: خانه‌های رنگی، پارک سبز و رودخانه‌ای که می‌درخشید. او فهمید دنیا خیلی بزرگ‌تر از آن چیزی است که فکر می‌کرد."}]}, {"title": "تصاویر سفر", "blocks": [{"type": "slideshow", "slides": [{"url": "/seed-images/cloud1.svg", "caption": ""}, {"url": "/seed-images/cloud2.svg", "caption": ""}, {"url": "/seed-images/cloud3.svg", "caption": ""}]}]}, {"title": "دوستی جدید", "blocks": [{"type": "text", "content": "ابر کوچولو با قطره کوچولو آشنا شد. قطره گفت: «من از ابرهای تو پایین می‌آیم!» ابر کوچولو خوشحال شد و گفت: «پس ما خانواده هستیم!» وقتی شب شد، ابر کوچولو و قطره کوچولو با هم به خواب رفتند و رویاهای درخشانی دیدند."}]}, {"title": "پیام دوستانه", "blocks": [{"type": "callout", "content": "همیشه دوست پیدا کن حتی در جاهای غیرمنتظره. دنیا پر از دوستان خوب است!", "style": "info"}]}]'::jsonb, 'book-28', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000029', 'حیوانات دوست‌داشتنی', 'بنیامین کوچک', 'کودک', 10, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "باغ وحش کوچولوها", "blocks": [{"type": "text", "content": "به باغ وحش کوچولوها خوش آمدید! اینجا همه حیوانات با هم دوست هستند. فیل کوچولو عاشق آب‌بازی است، زرافه کوچولو از درخت‌ها غذا می‌خورد و شیر کوچولو... خوب، شیر کوچولو فقط عاشق بغل گرفتن است!"}]}, {"title": "دوست‌های بامزه", "blocks": [{"type": "image", "url": "/seed-images/animal.svg", "caption": "حیوانات در کنار هم", "hotspots": [{"x": 25, "y": 45, "label": "فیل", "description": "فیل کوچولو با خرطومش بازی می‌کند"}, {"x": 55, "y": 35, "label": "زرافه", "description": "زرافه بلندقامت"}, {"x": 80, "y": 60, "label": "شیر", "description": "شیر کوچولو مهربان"}]}]}, {"title": "صداهای جالب", "blocks": [{"type": "text", "content": "فیل کوچولو ترومپت می‌زند: «پوووو!» زرافه کوچولو گردنش را تکان می‌دهد: «سرسرسر!» شیر کوچولو غرش می‌کند: «روووو!» حالا نوبت توست! صدای مورد علاقه‌ات را دربیار!"}]}, {"title": "خانه‌ها", "blocks": [{"type": "gallery", "images": [{"url": "/seed-images/house1.svg", "caption": ""}, {"url": "/seed-images/house2.svg", "caption": ""}, {"url": "/seed-images/house3.svg", "caption": ""}]}]}, {"title": "شب بخیر", "blocks": [{"type": "text", "content": "حالا همه حیوانات خوابیده‌اند. فیل کوچولو روی علف‌ها دراز کشیده. زرافه کوچولو گردنش را گره زده و خوابیده. شیر کوچوله هم بالشش را بغل گرفته. ستاره‌ها از بالا چشمک می‌زنند و ماه داستانی زمزمه می‌کند: «شب بخیر کوچولوها...»"}]}]'::jsonb, 'book-29', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000030', 'رنگین‌کمان بازی', 'نازنین کوچولو', 'کودک', 11, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "روز بارانی", "blocks": [{"type": "text", "content": "صبح که بیدار شدم، باران می‌بارید. ناراحت بودم چون نمی‌توانستم بیرون بروم. مادرم گفت: «بیا یک هفت‌رنگ درست کنیم!» چه ایده جالبی!"}]}, {"title": "رنگ‌ها", "blocks": [{"type": "image", "url": "/seed-images/rainbow.svg", "caption": "هفت رنگ زیبا", "hotspots": [{"x": 15, "y": 50, "label": "قرمز", "description": "رنگ عشق و شادی"}, {"x": 35, "y": 40, "label": "نارنجی", "description": "رنگ انرژی"}, {"x": 55, "y": 35, "label": "زرد", "description": "رنگ خورشید"}, {"x": 75, "y": 40, "label": "سبز", "description": "رنگ طبیعت"}, {"x": 90, "y": 50, "label": "آبی", "description": "رنگ آسمان"}]}]}, {"title": "بازی با رنگ‌ها", "blocks": [{"type": "text", "content": "قرمز و زرد را مخلوط کردم: نارنجی شد! آبی و زرد: سبز شد! قرمز و آبی: بنفش! واو! دنیای رنگ‌ها شگفت‌انگیز است. هر رنگ داستانی دارد و هر ترکیب رنگ جدید، داستانی جدید."}]}, {"title": "آثار هنری", "blocks": [{"type": "slideshow", "slides": [{"url": "/seed-images/art1.svg", "caption": ""}, {"url": "/seed-images/art2.svg", "caption": ""}, {"url": "/seed-images/art3.svg", "caption": ""}]}]}, {"title": "پیام رنگین‌کمان", "blocks": [{"type": "callout", "content": "هر کدام از ما مثل یک رنگ هستیم. وقتی کنار هم قرار می‌گیریم، یک رنگین‌کمان زیبا می‌شویم!", "style": "info"}]}]'::jsonb, 'book-30', 'fa', 'authored', true, true, 1)
ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, author = EXCLUDED.author, pages = EXCLUDED.pages;
INSERT INTO public.books (id, title, author, category, price, publisher_id, status, review_status, pages, slug, language, book_type, comments_enabled, first_published_paid, publish_complexity_factor)
VALUES ('11111111-1111-1111-1111-000000000031', 'کتاب آزمایشی پرصفحه', 'ناشر تست', 'تست', 10, '33333333-3333-3333-3333-333333333333', 'published', 'approved', '[{"title": "فصل 1", "blocks": [{"type": "text", "content": "این صفحه اول کتاب آزمایشی پرصفحه است. این کتاب برای تست عملکرد سیستم در شرایط واقعی با حجم بالای صفحات طراحی شده است. هر صفحه حدود صد کلمه دارد تا بتوان رفتار سیستم را در شرایط نزدیک به واقعیت بررسی کرد."}]}, {"title": "فصل 2", "blocks": [{"type": "text", "content": "در این فصل به معرفی مفاهیم پایه می‌پردازیم. ساختار کتاب به گونه‌ای طراحی شده که خواننده بتواند به صورت گام‌به‌گام با مطالب آشنا شود. تصاویر و نمودارهای تعاملی در صفحات بعدی کمک می‌کنند تا مفاهیم بهتر درک شوند."}]}, {"title": "فصل 3", "blocks": [{"type": "text", "content": "تاریخچه موضوع به قرن‌ها پیش برمی‌گردد. اولین نشانه‌های این علم در تمدن‌های کهن یافت شده است. باستان‌شناسان آثاری کشف کرده‌اند که نشان می‌دهد بشر هزاران سال پیش به این مفاهیم توجه داشته است."}]}, {"title": "فیلم آموزشی فصل 4", "blocks": [{"type": "video", "url": "/seed-images/sample.mp4", "caption": "ویدیوی توضیحی این فصل"}]}, {"title": "فصل 5", "blocks": [{"type": "text", "content": "کاربردهای عملی این دانش در زندگی روزمره فراوان است. از صنعت و پزشکی گرفته تا هنر و ورزش، همه جا شاهد تأثیر این علم هستیم. نوآوری‌های اخیر تحولات عظیمی ایجاد کرده‌اند."}]}, {"title": "نمودار تعاملی 6", "blocks": [{"type": "image", "url": "/seed-images/bigchart.svg", "caption": "نمودار داده‌ها", "hotspots": [{"x": 30, "y": 30, "label": "داده A", "description": "رشد سال اول"}, {"x": 70, "y": 70, "label": "داده B", "description": "رشد سال دوم"}]}]}, {"title": "فصل 7", "blocks": [{"type": "text", "content": "چالش‌های پیش رو بسیارند. محققان باید با محدودیت‌های منابع، مسائل اخلاقی و پیچیدگی‌های فنی دست‌وپنجه نرم کنند. همکاری بین‌المللی یکی از کلیدهای حل این چالش‌هاست."}]}, {"title": "فصل 8", "blocks": [{"type": "text", "content": "آموزش و پرورش نقش حیاتی در توسعه این علم دارد. نسل جدید باید با ابزارها و روش‌های نوین آشنا شود. برنامه‌های درسی نیاز به بازنگری دارند تا با پیشرفت‌های علمی همگام شوند."}]}, {"title": "فصل 9", "blocks": [{"type": "text", "content": "صنعت و بازار همواره از نوآوری‌ها استقبال کرده‌اند. شرکت‌های بزرگ سرمایه‌گذاری‌های کلانی در تحقیق و توسعه انجام می‌دهند. رقابت سالم باعث پیشرفت سریع‌تر شده است."}]}, {"title": "فصل 10", "blocks": [{"type": "text", "content": "جمع‌بندی و نتیجه‌گیری این فصل نشان می‌دهد که ما در آستانه تحولی بزرگ هستیم. گام‌های بعدی نیازمند همکاری همه بخش‌های جامعه است. آینده در دستان ماست و با تلاش جمعی می‌توانیم به اهدافمان برسیم."}]}, {"title": "بخش 11", "blocks": [{"type": "text", "content": "این بخش به تفصیل به بررسی مثال‌های کاربردی می‌پردازد. هر مثال با شرایط واقعی طراحی شده و خواننده می‌تواند آن‌ها را در موقعیت‌های مشابه به کار گیرد. تمرین‌ها در انتهای بخش کمک می‌کنند تا مهارت‌ها تقویت شوند."}]}, {"title": "بخش 12", "blocks": [{"type": "text", "content": "توسعه این حوزه نیازمند سرمایه‌گذاری در زیرساخت‌هاست. مراکز تحقیقاتی باید به تجهیزات پیشرفته دسترسی داشته باشند. همچنین ایجاد شبکه‌های همکاری بین دانشگاه‌ها و صنعت ضروری است."}]}, {"title": "بخش 13", "blocks": [{"type": "text", "content": "سیاست‌گذاران نقش مهمی در تسهیل این روند دارند. قوانین حمایتی، معافیت‌های مالیاتی و تسهیلات تحقیقاتی می‌تواند رشد را تسریع کند. تجربه کشورهای پیشرو الگوی خوبی است."}]}, {"title": "بخش 14", "blocks": [{"type": "text", "content": "مردم عادی هم می‌توانند سهمی در این پیشرفت داشته باشند. آموزش همگانی، شرکت در نظرسنجی‌ها و حمایت از طرح‌های محلی از راه‌های مشارکت است. هر ایده‌ای می‌تواند جرقه‌ای باشد."}]}, {"title": "بخش 15", "blocks": [{"type": "text", "content": "محیط زیست همواره باید در نظر گرفته شود. توسعه پایدار یعنی پیشرفت بدون آسیب به طبیعت. فناوری‌های سبز و انرژی‌های تجدیدپذیر راه‌حل‌های مناسبی هستند. آینده متعلق به کسانی است که به زمین احترام می‌گذارند."}]}, {"title": "بخش 16", "blocks": [{"type": "text", "content": "فرهنگ و هنر این حوزه را غنی‌تر می‌کنند. خلاقیت انسان‌ها هیچ مرزی نمی‌شناسد. آثار هنری الهام‌بخش نسل‌های بعدی خواهند بود. زیبایی در سادگی است و سادگی در عمق."}]}, {"title": "بخش 17", "blocks": [{"type": "text", "content": "ورزش و سلامت از دیگر حوزه‌های تأثیرپذیر هستند. ورزشکاران با استفاده از دانش نوین بهتر عمل می‌کنند. پزشکی شخصی‌سازی شده به درمان دقیق‌تر کمک می‌کند. سلامت جامعه سرمایه اصلی هر کشور است."}]}, {"title": "بخش 18", "blocks": [{"type": "text", "content": "اقتصاد و بازار کار نیز دستخوش تغییرات شده‌اند. مشاغل جدیدی ایجاد شده و برخی مشاغل قدیمی منسوخ شده‌اند. آموزش مهارت‌های جدید برای نیروی کار ضروری است. انعطاف‌پذیری کلید موفقیت در بازار کار آینده است."}]}, {"title": "بخش 19", "blocks": [{"type": "text", "content": "این بخش به تفصیل به بررسی مثال‌های کاربردی می‌پردازد. هر مثال با شرایط واقعی طراحی شده و خواننده می‌تواند آن‌ها را در موقعیت‌های مشابه به کار گیرد. تمرین‌ها در انتهای بخش کمک می‌کنند تا مهارت‌ها تقویت شوند."}]}, {"title": "بخش 20", "blocks": [{"type": "text", "content": "توسعه این حوزه نیازمند سرمایه‌گذاری در زیرساخت‌هاست. مراکز تحقیقاتی باید به تجهیزات پیشرفته دسترسی داشته باشند. همچنین ایجاد شبکه‌های همکاری بین دانشگاه‌ها و صنعت ضروری است."}]}, {"title": "بخش 21", "blocks": [{"type": "text", "content": "سیاست‌گذاران نقش مهمی در تسهیل این روند دارند. قوانین حمایتی، معافیت‌های مالیاتی و تسهیلات تحقیقاتی می‌تواند رشد را تسریع کند. تجربه کشورهای پیشرو الگوی خوبی است."}]}, {"title": "بخش 22", "blocks": [{"type": "text", "content": "مردم عادی هم می‌توانند سهمی در این پیشرفت داشته باشند. آموزش همگانی، شرکت در نظرسنجی‌ها و حمایت از طرح‌های محلی از راه‌های مشارکت است. هر ایده‌ای می‌تواند جرقه‌ای باشد."}]}, {"title": "بخش 23", "blocks": [{"type": "text", "content": "محیط زیست همواره باید در نظر گرفته شود. توسعه پایدار یعنی پیشرفت بدون آسیب به طبیعت. فناوری‌های سبز و انرژی‌های تجدیدپذیر راه‌حل‌های مناسبی هستند. آینده متعلق به کسانی است که به زمین احترام می‌گذارند."}]}, {"title": "بخش 24", "blocks": [{"type": "text", "content": "فرهنگ و هنر این حوزه را غنی‌تر می‌کنند. خلاقیت انسان‌ها هیچ مرزی نمی‌شناسد. آثار هنری الهام‌بخش نسل‌های بعدی خواهند بود. زیبایی در سادگی است و سادگی در عمق."}]}, {"title": "بخش 25", "blocks